{
  "competency_groups": [
    {
      "code": "C1",
      "title": "Some Basic Concepts of Chemistry",
      "description": "Equip learners with tools to understand the working of chemistry, develop conceptual foundations for real-life application, and enable representation at macroscopic, molecular, and symbolic levels.",
      "competencies": [
        "Understand nature of matter, properties, measurement, and uncertainty in measurement.",
        "Apply laws of chemical combination and Dalton's atomic theory to calculate atomic/molecular masses.",
        "Perform stoichiometric calculations using mole concept and percentage composition."
      ],
      "unit_name": "Some Basic Concepts of Chemistry",
      "chapter_name": "Some Basic Concepts of Chemistry"
    },
    {
      "code": "C2",
      "title": "Structure of Atom",
      "description": "Enable learners to identify patterns in atomic structure and form connections underlying chemical phenomena through quantum mechanical understanding.",
      "competencies": [
        "Trace the discovery of sub-atomic particles and evolution from Bohr's model to Quantum Mechanical Model."
      ],
      "unit_name": "Structure of Atom",
      "chapter_name": "Structure of Atom"
    },
    {
      "code": "C3",
      "title": "Classification of Elements and Periodicity in Properties",
      "description": "Enable learners to classify elements, understand periodic trends, and identify patterns underlying chemical properties.",
      "competencies": [
        "Understand the genesis of periodic classification and modern periodic law."
      ],
      "unit_name": "Classification of Elements and Periodicity in Properties",
      "chapter_name": "Classification of Elements and Periodicity in Properties"
    },
    {
      "code": "C4",
      "title": "Chemical Bonding and Molecular Structure",
      "description": "Develop ability to apply bonding theories to explain molecular structure, hybridization, and intermolecular forces.",
      "competencies": [
        "Apply Kossel-Lewis approach, VSEPR theory, Valence Bond Theory, and Molecular Orbital Theory."
      ],
      "unit_name": "Chemical Bonding and Molecular Structure",
      "chapter_name": "Chemical Bonding and Molecular Structure"
    },
    {
      "code": "C5",
      "title": "Thermodynamics",
      "description": "Enable learners to represent chemical phenomena at macroscopic levels through thermodynamic terms, enthalpy changes, and spontaneity.",
      "competencies": [
        "Apply concepts of calorimetry, Gibbs energy change, and equilibrium conditions."
      ],
      "unit_name": "Thermodynamics",
      "chapter_name": "Thermodynamics"
    },
    {
      "code": "C6",
      "title": "Equilibrium",
      "description": "Enable learners to identify patterns in dynamic equilibrium and apply laws of chemical equilibrium to physical and chemical processes.",
      "competencies": [
        "Analyze homogeneous/heterogeneous equilibria, ionic equilibrium, buffer solutions, and solubility equilibria."
      ],
      "unit_name": "Equilibrium",
      "chapter_name": "Equilibrium"
    },
    {
      "code": "C7",
      "title": "Redox Reactions",
      "description": "Develop problem-solving skills to analyze electron transfer reactions and oxidation numbers.",
      "competencies": [
        "Classify redox reactions in terms of electron transfer and electrode processes."
      ],
      "unit_name": "Redox Reactions",
      "chapter_name": "Redox Reactions"
    },
    {
      "code": "C8",
      "title": "Organic Chemistry: Some basic Principles and Techniques",
      "description": "Enable learners to represent organic compounds structurally, understand reaction mechanisms, and apply purification techniques.",
      "competencies": [
        "Apply nomenclature rules, identify isomerism, and analyze fundamental concepts of organic reaction mechanisms."
      ],
      "unit_name": "Organic Chemistry: Some basic Principles and Techniques",
      "chapter_name": "Some basic Principles and Techniques"
    },
    {
      "code": "C9",
      "title": "Hydrocarbons",
      "description": "Enable learners to classify hydrocarbons, understand their properties, and identify carcinogenic/toxic effects.",
      "competencies": [
        "Differentiate between alkanes, alkenes, alkynes, and aromatic hydrocarbons."
      ],
      "unit_name": "Hydrocarbons",
      "chapter_name": "Hydrocarbons"
    },
    {
      "code": "C10",
      "title": "Solutions",
      "description": "Develop conceptual foundations to express concentration, understand solubility, and apply colligative properties.",
      "competencies": [
        "Calculate molar mass using colligative properties and distinguish between ideal and non-ideal solutions."
      ],
      "unit_name": "Unit 1: Solutions",
      "chapter_name": "Solutions"
    },
    {
      "code": "C11",
      "title": "Electrochemistry",
      "description": "Enable learners to represent electrochemical phenomena and apply Nernst equation for cell potential calculations.",
      "competencies": [
        "Analyze galvanic cells, electrolytic cells, batteries, fuel cells, and corrosion processes."
      ],
      "unit_name": "Unit 2: Electrochemistry",
      "chapter_name": "Electrochemistry"
    },
    {
      "code": "C12",
      "title": "Chemical Kinetics",
      "description": "Develop problem-solving skills to analyze factors influencing reaction rates and temperature dependence.",
      "competencies": [
        "Apply integrated rate equations and collision theory of chemical reactions."
      ],
      "unit_name": "Unit 3: Chemical Kinetics",
      "chapter_name": "Chemical Kinetics"
    },
    {
      "code": "C13",
      "title": "d and f Block Elements",
      "description": "Enable learners to identify patterns in transition elements, lanthanoids, and actinoids regarding electronic configuration and properties.",
      "competencies": [
        "Correlate position in periodic table with general properties of d-block and f-block elements."
      ],
      "unit_name": "Unit 4: d and f Block Elements",
      "chapter_name": "d -and f -Block Elements"
    },
    {
      "code": "C14",
      "title": "Coordination Compounds",
      "description": "Enable learners to represent coordination compounds using IUPAC nomenclature and understand bonding theories.",
      "competencies": [
        "Apply Werner's theory, identify isomerism, and analyze metal carbonyl bonding."
      ],
      "unit_name": "Unit 5: Coordination Compounds",
      "chapter_name": "Coordination Compounds"
    },
    {
      "code": "C15",
      "title": "Haloalkanes and Haloarenes",
      "description": "Develop ability to apply nomenclature rules, understand C-X bond nature, and predict chemical reactions.",
      "competencies": [
        "Differentiate methods of preparation and physical properties of halo compounds."
      ],
      "unit_name": "Unit 6: Haloalkanes and Haloarenes",
      "chapter_name": "Haloalkanes and Haloarenes"
    },
    {
      "code": "C16",
      "title": "Alcohols, Phenols and Ethers",
      "description": "Enable learners to classify organic compounds based on functional groups and understand their commercial importance.",
      "competencies": [
        "Apply nomenclature rules and distinguish structures of alcohols, phenols, and ethers."
      ],
      "unit_name": "Unit 7: Alcohols, Phenols and Ethers",
      "chapter_name": "Alcohols, Phenols and Ethers"
    },
    {
      "code": "C17",
      "title": "Aldehydes, Ketones and Carboxylic Acids",
      "description": "Develop problem-solving skills to analyze preparation methods, physical properties, and chemical reactions of carbonyl compounds.",
      "competencies": [
        "Differentiate nomenclature and structures of aldehydes, ketones, and carboxylic acids."
      ],
      "unit_name": "Unit 8: Aldehydes, Ketones and Carboxylic Acids",
      "chapter_name": "Aldehydes, Ketones and Carboxylic Acids"
    },
    {
      "code": "C18",
      "title": "Amines",
      "description": "Enable learners to classify amines, understand diazonium salts synthesis, and apply reactions in aromatic compound synthesis.",
      "competencies": [
        "Apply nomenclature rules and analyze chemical reactions of primary amines."
      ],
      "unit_name": "Unit 9: Amines",
      "chapter_name": "Amines"
    },
    {
      "code": "C19",
      "title": "Biomolecules",
      "description": "Prepare learners to contribute to frontier research areas related to biology and medicine through understanding biomolecular structures.",
      "competencies": [
        "Identify carbohydrates, proteins, enzymes, vitamins, nucleic acids, and hormones."
      ],
      "unit_name": "Unit 10: Biomolecules",
      "chapter_name": "Biomolecules"
    }
  ]
}
